package main

import (
	"context"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/server/authn/method"
	middlewarecommon "go.flipt.io/flipt/internal/server/authn/middleware/common"
	grpcmiddleware "go.flipt.io/flipt/internal/server/authn/middleware/grpc"
	"go.flipt.io/flipt/internal/storage/authn/memory"
	"go.uber.org/zap"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc/metadata"
)

// TestRegression demonstrates the authentication cookie handling bugs
func TestRegression(t *testing.T) {
	logger := zaptest.NewLogger(t)

	t.Run("CookieTokenExtractionFailure", func(t *testing.T) {
		// This test demonstrates that browser cookies with valid tokens are rejected
		// because the authentication middleware does not properly extract them.

		// Create an authentication token store with a valid token
		store := memory.NewStore(logger)
		ctx := context.Background()

		clientToken, storedAuth, err := store.CreateAuthentication(
			ctx,
			nil, // method will use default
		)
		require.NoError(t, err)
		require.NotNil(t, storedAuth)

		// Simulate an HTTP request with the token in a cookie (typical browser behavior)
		req := httptest.NewRequest("GET", "/api/v1/flags", nil)
		req.AddCookie(&http.Cookie{
			Name:  middlewarecommon.TokenCookieKey,
			Value: clientToken,
		})

		// Test 1: ForwardCookies should extract the cookie and convert it to gRPC metadata
		// This is currently broken - let's verify the bug
		md := method.ForwardCookies(context.Background(), req)

		// BUG 1: ForwardCookies has a typo - it always uses stateCookieKey
		// Even though we passed tokenCookieKey in the request, the metadata doesn't
		// contain the token under the correct key
		//
		// Expected: md should have "grpcgateway-cookie" with "flipt_client_token=<token>"
		// Actual: md is empty or malformed because of the bug in ForwardCookies
		cookie := req.Cookies()
		require.Len(t, cookie, 1)
		require.Equal(t, middlewarecommon.TokenCookieKey, cookie[0].Name)

		// This is what SHOULD happen but doesn't:
		// The ForwardCookies function should properly format the cookie for gRPC Gateway
		// and place it under the "grpcgateway-cookie" key with HTTP Cookie format:
		// "flipt_client_token=<value>"
		//
		// Let's verify the bug exists by checking if the metadata is properly formatted
		if len(md) > 0 {
			// If there's any metadata, check if it's formatted correctly
			// It should be under "grpcgateway-cookie" key in HTTP Cookie format
			cookieHeader := md.Get("grpcgateway-cookie")
			if len(cookieHeader) > 0 {
				// The cookie header should contain "flipt_client_token="
				assert.Contains(t, cookieHeader[0], "flipt_client_token=",
					"Cookie should be in HTTP Cookie format under grpcgateway-cookie key")
			} else {
				// No cookie in the expected place - this is the bug
				t.Logf("BUG CONFIRMED: ForwardCookies did not put cookie under 'grpcgateway-cookie' key")
			}
		} else {
			// Empty metadata - the bug manifests as lost cookies
			t.Logf("BUG CONFIRMED: ForwardCookies produced empty metadata, cookie was lost")
		}

		// Test 2: Even if we manually construct the correct metadata,
		// verify that the gRPC middleware can extract it properly
		correctMetadata := metadata.MD{
			"grpcgateway-cookie": []string{"flipt_client_token=" + clientToken},
		}

		ctx = metadata.NewIncomingContext(context.Background(), correctMetadata)

		// This should work if the middleware is correct
		retrievedAuth, err := store.GetAuthenticationByClientToken(ctx, clientToken)
		assert.NoError(t, err)
		assert.Equal(t, storedAuth.Id, retrievedAuth.Id)
		assert.Equal(t, storedAuth.Method, retrievedAuth.Method)
	})

	t.Run("ServerSkipAuthenticationBehavior", func(t *testing.T) {
		// This test demonstrates that while the SkipsAuthenticationServer interface exists,
		// there's no mechanism for HTTP-level authentication to skip authentication
		// for certain servers (e.g., delegated auth flows)

		logger := zaptest.NewLogger(t)
		store := memory.NewStore(logger)
		ctx := context.Background()

		// Create a valid token
		clientToken, _, err := store.CreateAuthentication(
			ctx,
			nil,
		)
		require.NoError(t, err)

		// Test Case 1: gRPC level skipping works
		// The middleware has a mechanism to skip authentication for gRPC servers
		// that implement SkipsAuthenticationServer interface

		// Mock server that skips authentication
		type mockServer struct{}

		func (m *mockServer) SkipsAuthentication(ctx context.Context) bool {
			return true
		}

		// This would work at gRPC level with the WithServerSkipsAuthentication option
		// but there's no equivalent mechanism for HTTP requests

		// Test Case 2: HTTP level authentication cannot be skipped
		// When using gRPC Gateway (HTTP to gRPC bridge), there's no way to
		// configure which HTTP routes should skip authentication

		// Simulate an HTTP request to an authentication method endpoint
		// that should not require authentication (like OIDC authorize callback)
		req := httptest.NewRequest("GET", "/auth/v1/method/oidc/authorize", nil)

		// This request should be able to skip authentication because it's part of the
		// authentication flow itself, but there's no mechanism to configure this
		// at the HTTP middleware level in authn/middleware/http/middleware.go

		// The HTTP middleware (Handler function) only handles logout (PUT /auth/v1/self/expire)
		// and error handling for unauthenticated responses.
		// There's no whitelist or skip mechanism for authentication-related endpoints

		// Add a cookie even though this should skip auth
		req.AddCookie(&http.Cookie{
			Name:  middlewarecommon.TokenCookieKey,
			Value: clientToken,
		})

		// When this request goes through gRPC Gateway without proper cookie forwarding,
		// it will fail authentication even though it should be allowed to proceed

		// Verify that the request has a cookie
		cookies := req.Cookies()
		require.Len(t, cookies, 1)

		// But the ForwardCookies bug means this cookie never makes it to the gRPC layer
		md := method.ForwardCookies(context.Background(), req)
		if len(md) == 0 {
			t.Logf("BUG CONFIRMED: Server skip logic is bypassed for HTTP requests "+
				"because ForwardCookies fails to forward the cookie (%s)",
				middlewarecommon.TokenCookieKey)
		}
	})

	t.Run("CookieForwardingMetadataFormat", func(t *testing.T) {
		// This test verifies the correct format for cookies in gRPC metadata
		// and demonstrates what the current implementation is missing

		store := memory.NewStore(logger)
		ctx := context.Background()

		clientToken, _, err := store.CreateAuthentication(ctx, nil)
		require.NoError(t, err)

		// Create an HTTP request with a cookie
		req := httptest.NewRequest("GET", "/api/v1/flags", nil)
		cookie := &http.Cookie{
			Name:  middlewarecommon.TokenCookieKey,
			Value: clientToken,
		}
		req.AddCookie(cookie)

		// Test: ForwardCookies should produce metadata in the correct format
		md := method.ForwardCookies(context.Background(), req)

		// Expected behavior (what should happen):
		// The metadata should have a "grpcgateway-cookie" key with the cookie in HTTP format
		// Format: "flipt_client_token=<token_value>"

		// Get what ForwardCookies actually produced
		t.Logf("ForwardCookies metadata keys: %v", md)

		// The middleware later expects to parse this with cookieFromMetadata which does:
		//   (&http.Request{Header: http.Header{"Cookie": md.Get(cookieHeaderKey)}}).Cookie(key)
		// This requires the "grpcgateway-cookie" key to have the value in HTTP Cookie format

		// Manually verify the middleware can extract a properly formatted cookie
		properlyFormatted := metadata.MD{
			"grpcgateway-cookie": []string{cookie.Name + "=" + cookie.Value},
		}

		// Simulate what clientTokenFromMetadata should do
		testReq := &http.Request{
			Header: http.Header{
				"Cookie": properlyFormatted.Get("grpcgateway-cookie"),
			},
		}

		// This should work
		extracted, err := testReq.Cookie(middlewarecommon.TokenCookieKey)
		assert.NoError(t, err)
		assert.Equal(t, clientToken, extracted.Value)

		// But ForwardCookies doesn't produce this format, which is the bug
		if len(md) == 0 {
			t.Logf("BUG: ForwardCookies produced empty metadata instead of gRPC Gateway cookie format")
		} else {
			// Check if it's in the right format
			gatewayCookie := md.Get("grpcgateway-cookie")
			if len(gatewayCookie) == 0 {
				t.Logf("BUG: Cookie is not under 'grpcgateway-cookie' key in metadata")
				t.Logf("ForwardCookies produced: %v", md)
			}
		}
	})

	t.Run("TokenExpirationWithCookie", func(t *testing.T) {
		// Additional test: Verify that expired tokens in cookies are properly rejected

		store := memory.NewStore(logger)
		ctx := context.Background()

		// Create an expired token
		expiredToken, _, err := store.CreateAuthentication(
			ctx,
			&struct {
				ExpiresAt *time.Time
			}{
				ExpiresAt: func() *time.Time {
					t := time.Now().Add(-1 * time.Hour)
					return &t
				}(),
			},
		)
		require.NoError(t, err)

		// Try to use it in a cookie
		req := httptest.NewRequest("GET", "/api/v1/flags", nil)
		req.AddCookie(&http.Cookie{
			Name:  middlewarecommon.TokenCookieKey,
			Value: expiredToken,
		})

		// Due to the ForwardCookies bug, this cookie won't even be extracted
		// So the middleware won't get a chance to check if it's expired
		md := method.ForwardCookies(context.Background(), req)

		if len(md) == 0 {
			t.Logf("BUG: Expired token in cookie cannot be properly rejected because "+
				"ForwardCookies failed to extract it (returned empty metadata)")
		} else {
			// If metadata was properly formatted, the next layer should reject the expired token
			// But that never happens because of the earlier bug
			t.Logf("ForwardCookies produced metadata, would need to verify expiration handling")
		}
	})
}

