		// it will fail authentication even though it should be allowed to proceed

		// Verify that the request has a cookie
		cookies := req.Cookies()
		require.Len(t, cookies, 1)

		// But the ForwardCookies bug means this cookie never makes it to the gRPC layer
		md := method.ForwardCookies(context.Background(), req)
		if len(md) == 0 {
			t.Logf("BUG CONFIRMED: Server skip logic is bypassed for HTTP requests "+
				"because ForwardCookies fails to forward the cookie (%s)",
				middlewarecommon.TokenCookieKey)
		}
	})

	t.Run("CookieForwardingMetadataFormat", func(t *testing.T) {
		// This test verifies the correct format for cookies in gRPC metadata
		// and demonstrates what the current implementation is missing

		store := memory.NewStore(logger)
		ctx := context.Background()

		clientToken, _, err := store.CreateAuthentication(ctx, nil)
		require.NoError(t, err)

		// Create an HTTP request with a cookie
		req := httptest.NewRequest("GET", "/api/v1/flags", nil)
		cookie := &http.Cookie{
			Name:  middlewarecommon.TokenCookieKey,
			Value: clientToken,
		}
		req.AddCookie(cookie)

		// Test: ForwardCookies should produce metadata in the correct format
		md := method.ForwardCookies(context.Background(), req)

		// Expected behavior (what should happen):
		// The metadata should have a "grpcgateway-cookie" key with the cookie in HTTP format
		// Format: "flipt_client_token=<token_value>"

		// Get what ForwardCookies actually produced
		t.Logf("ForwardCookies metadata keys: %v", md)

		// The middleware later expects to parse this with cookieFromMetadata which does:
		//   (&http.Request{Header: http.Header{"Cookie": md.Get(cookieHeaderKey)}}).Cookie(key)
		// This requires the "grpcgateway-cookie" key to have the value in HTTP Cookie format

		// Manually verify the middleware can extract a properly formatted cookie
		properlyFormatted := metadata.MD{
			"grpcgateway-cookie": []string{cookie.Name + "=" + cookie.Value},
