				stateCookie: "",
				tokenCookie: "token_xyz789",
				expectMetadata: map[string]string{
					"flipt_client_token": "token_xyz789",
				},
				description: "Token cookie alone must be preserved",
			},
		}

		for _, tt := range tests {
			t.Run(tt.name, func(t *testing.T) {
				t.Logf("Test: %s", tt.description)

				// Simulate current buggy implementation
