222: func jwtClaimsToMetadata(jwtClaims map[string]any, claimsMapping map[string]string) map[string]string {
223: 	md := map[string]string{}
224: 
225: 	for k, v := range jwtClaims {
226: 		if strings.HasPrefix(k, "io.flipt.auth") {
227: 			md[k] = fmt.Sprintf("%v", v)
228: 			continue
229: 		}
230: 
231: 		if v, ok := v.(string); ok && k == "iss" {
232: 			md["io.flipt.auth.jwt.issuer"] = v
233: 			continue
234: 		}
235: 	}
236: 
237: 	defaultMappings := map[string]string{
238: 		"email":   "/user/email",
239: 		"sub":     "/user/sub",
240: 		"picture": "/user/image",
241: 		"name":    "/user/name",
242: 		"role":    "/user/role",
243: 	}
244: 
245: 	effectiveMappings := maps.Clone(defaultMappings)
246: 	maps.Copy(effectiveMappings, claimsMapping)
247: 
248: 	// Extract user attributes using the effective mappings
249: 	for attribute, jsonPointerExpr := range effectiveMappings {
250: 		if jsonPointerExpr == "" {
251: 			continue
252: 		}
253: 
254: 		ptr, err := jsonpointer.New(jsonPointerExpr)
255: 		if err != nil {
256: 			continue // Skip invalid JSON pointer expressions
257: 		}
258: 
259: 		value, _, err := ptr.Get(jwtClaims)
260: 		if err != nil {
261: 			continue // Skip if the pointer doesn't resolve
262: 		}
263: 
264: 		md[fmt.Sprintf("io.flipt.auth.jwt.%s", attribute)] = fmt.Sprintf("%v", value)
265: 	}
266: 
267: 	return md
268: }
