270: // authenticateJWT authenticates a JWT found in the incoming request metadata and returns a new context with the authenticated authentication instance.
271: func authenticateJWT(ctx context.Context, logger *zap.Logger, claimsMapping map[string]string, validator method.JWTValidator) (context.Context, error) {
272: 	md, ok := metadata.FromIncomingContext(ctx)
273: 	if !ok {
274: 		logger.Error("unauthenticated", zap.String("reason", "metadata not found on context"))
275: 		return ctx, errUnauthenticated
276: 	}
277: 
278: 	token, err := jwtFromMetadata(md)
279: 	if err != nil {
280: 		logger.Error("unauthenticated",
281: 			zap.String("reason", "no authorization provided"),
282: 			zap.Error(err))
283: 
284: 		return ctx, errUnauthenticated
285: 	}
286: 
287: 	jwtClaims, err := validator.Validate(ctx, token)
288: 	if err != nil {
289: 		logger.Error("unauthenticated",
290: 			zap.String("reason", "error validating jwt"),
291: 			zap.Error(err))
292: 
293: 		if errs.Is(err, context.Canceled) {
294: 			err = status.Error(codes.Canceled, err.Error())
295: 			return ctx, err
296: 		}
297: 
298: 		if errs.Is(err, context.DeadlineExceeded) {
299: 			err = status.Error(codes.DeadlineExceeded, err.Error())
300: 			return ctx, err
301: 		}
302: 
303: 		return ctx, errUnauthenticated
304: 	}
305: 
306: 	return ContextWithAuthentication(ctx, &authrpc.Authentication{
307: 		Method:   authrpc.Method_METHOD_JWT,
308: 		Metadata: jwtClaimsToMetadata(jwtClaims, claimsMapping),
309: 	}), nil
310: }
