377: // authenticateClientToken authenticates a client token found in the incoming request metadata and returns a new context with the authenticated authentication instance.
378: func authenticateClientToken(ctx context.Context, logger *zap.Logger, authenticator ClientTokenAuthenticator) (context.Context, error) {
379: 	md, ok := metadata.FromIncomingContext(ctx)
380: 	if !ok {
381: 		logger.Error("unauthenticated", zap.String("reason", "metadata not found on context"))
382: 		return ctx, errUnauthenticated
383: 	}
384: 
385: 	clientToken, err := clientTokenFromMetadata(md)
386: 	if err != nil {
387: 		logger.Error("unauthenticated",
388: 			zap.String("reason", "no authorization provided"),
389: 			zap.Error(err))
390: 
391: 		return ctx, errUnauthenticated
392: 	}
393: 
394: 	auth, err := authenticator.GetAuthenticationByClientToken(ctx, clientToken)
395: 	if err != nil {
396: 		logger.Error("unauthenticated",
397: 			zap.String("reason", "error retrieving authentication for client token"),
398: 			zap.Error(err))
399: 
400: 		if errs.Is(err, context.Canceled) {
401: 			err = status.Error(codes.Canceled, err.Error())
402: 			return ctx, err
403: 		}
404: 
405: 		if errs.Is(err, context.DeadlineExceeded) {
406: 			err = status.Error(codes.DeadlineExceeded, err.Error())
407: 			return ctx, err
408: 		}
409: 
410: 		return ctx, errUnauthenticated
411: 	}
412: 
413: 	if auth.ExpiresAt != nil && auth.ExpiresAt.AsTime().Before(time.Now()) {
414: 		logger.Error("unauthenticated",
415: 			zap.String("reason", "authorization expired"),
416: 			zap.String("authentication_id", auth.Id),
417: 		)
418: 		return ctx, errUnauthenticated
419: 	}
420: 
421: 	return ContextWithAuthentication(ctx, auth), nil
422: }
