424: // EmailMatchingUnaryInterceptor is a grpc.UnaryServerInterceptor only used in the case where the user is using OIDC
425: // and wants to whitelist a group of users issuing operations against the Flipt server.
426: func EmailMatchingUnaryInterceptor(logger *zap.Logger, rgxs []*regexp.Regexp, o ...containers.Option[InterceptorOptions]) grpc.UnaryServerInterceptor {
427: 	var opts InterceptorOptions
428: 	containers.ApplyAll(&opts, o...)
429: 
430: 	return func(ctx context.Context, req any, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (any, error) {
431: 		// skip auth for any preconfigured servers
432: 		if skipped(ctx, info.Server, opts) {
433: 			logger.Debug("skipping authentication for server", zap.String("method", info.FullMethod))
434: 			return handler(ctx, req)
435: 		}
436: 
437: 		auth := GetAuthenticationFrom(ctx)
438: 		if auth == nil {
439: 			logger.Error("unauthenticated", zap.String("reason", "authentication required for email matching"))
440: 			return nil, errUnauthenticated
441: 		}
442: 
443: 		// this mechanism only applies to authentications created using OIDC
444: 		if auth.Method != authrpc.Method_METHOD_OIDC {
445: 			return handler(ctx, req)
446: 		}
447: 
448: 		email, ok := auth.Metadata["io.flipt.auth.oidc.email"]
449: 		if !ok {
450: 			logger.Debug("no email provided but required for auth")
451: 			return ctx, errUnauthenticated
452: 		}
453: 
454: 		matched := false
455: 
456: 		for _, rgx := range rgxs {
457: 			if matched = rgx.MatchString(email); matched {
458: 				break
459: 			}
460: 		}
461: 
462: 		if !matched {
463: 			logger.Error("unauthenticated", zap.String("reason", "email is not allowed"))
464: 			return ctx, errUnauthenticated
465: 		}
466: 
467: 		return handler(ctx, req)
468: 	}
469: }
