471: // clientTokenFromMetadata extracts a client token found in the incoming request metadata
472: // and returns the client token.
473: func clientTokenFromMetadata(md metadata.MD) (string, error) {
474: 	if authenticationHeader := md.Get(authenticationHeaderKey); len(authenticationHeader) > 0 {
475: 		return fromAuthorization(authenticationHeader[0], authenticationSchemeBearer)
476: 	}
477: 
478: 	cookie, err := cookieFromMetadata(md, middlewarecommon.TokenCookieKey)
479: 	if err != nil {
480: 		return "", err
481: 	}
482: 
483: 	return cookie.Value, nil
484: }
