486: // cookieFromMetadata extracts a cookie found in the incoming request metadata
487: // and returns the cookie.
488: func cookieFromMetadata(md metadata.MD, key string) (*http.Cookie, error) {
489: 	// sadly net/http does not expose cookie parsing
490: 	// outside of http.Request.
491: 	// so instead we fabricate a request around the cookie
492: 	// in order to extract it appropriately.
493: 	return (&http.Request{
494: 		Header: http.Header{"Cookie": md.Get(cookieHeaderKey)},
495: 	}).Cookie(key)
