145: // CreateAuthentication creates a new instance of an Authentication and returns a unique clientToken
146: // string which can be used to retrieve the Authentication again via GetAuthenticationByClientToken.
147: func (s *Store) CreateAuthentication(_ context.Context, r *authn.CreateAuthenticationRequest) (string, *rpcauth.Authentication, error) {
148: 	if r.ExpiresAt != nil && !r.ExpiresAt.IsValid() {
149: 		return "", nil, errors.ErrInvalidf("invalid expiry time: %v", r.ExpiresAt)
150: 	}
151: 
152: 	var (
153: 		now            = s.now()
154: 		clientToken    = r.ClientToken
155: 		authentication = &rpcauth.Authentication{
156: 			Id:        s.generateID(),
157: 			Method:    r.Method,
158: 			Metadata:  r.Metadata,
159: 			ExpiresAt: r.ExpiresAt,
160: 			CreatedAt: now,
161: 			UpdatedAt: now,
162: 		}
163: 	)
164: 
165: 	// if no client token is provided, generate a new one
166: 	if clientToken == "" {
167: 		clientToken = s.generateToken()
168: 	}
169: 
170: 	hashedToken, err := authn.HashClientToken(clientToken)
171: 	if err != nil {
172: 		return "", nil, fmt.Errorf("creating authentication: %w", err)
173: 	}
174: 
175: 	s.mu.Lock()
176: 	s.byToken[hashedToken] = authentication
177: 	s.byID[authentication.Id] = authentication
178: 	s.mu.Unlock()
179: 
180: 	return clientToken, authentication, nil
181: }
182: 
183: // GetAuthenticationByClientToken retrieves an instance of Authentication from the backing
184: // store using the provided clientToken string as the key.
185: func (s *Store) GetAuthenticationByClientToken(ctx context.Context, clientToken string) (*rpcauth.Authentication, error) {
186: 	hashedToken, err := authn.HashClientToken(clientToken)
187: 	if err != nil {
188: 		return nil, fmt.Errorf("getting authentication by token: %w", err)
189: 	}
190: 
191: 	s.mu.Lock()
192: 	authentication, ok := s.byToken[hashedToken]
193: 	s.mu.Unlock()
194: 	if !ok {
195: 		return nil, errors.ErrNotFound("getting authentication by token")
196: 	}
197: 
198: 	return authentication, nil
199: }
