// TestCookieTimingAndExpiration verifies cookie handling with time-based tokens
func TestCookieTimingAndExpiration(t *testing.T) {
	t.Run("ExpiredTokenInCookie", func(t *testing.T) {
		// Even if the ForwardCookies bug were fixed, verify that
		// expired tokens in cookies are properly rejected

		logger := zaptest.NewLogger(t)
		store := memory.NewStore(logger)
		ctx := context.Background()

		// Create an expired token
		expiryTime := time.Now().UTC().Add(-24 * time.Hour)
		expiredToken, _, err := store.CreateAuthentication(
			ctx,
			&storageauthn.CreateAuthenticationRequest{
				Method:    rpcauth.Method_METHOD_TOKEN,
				ExpiresAt: timestamppb.New(expiryTime),
			},
		)
		require.NoError(t, err)

		// Put it in a cookie (as browser would)
		req := httptest.NewRequest("GET", "/api/v1/flags", nil)
		req.AddCookie(&http.Cookie{
			Name:  middlewarecommon.TokenCookieKey,
			Value: expiredToken,
		})

		// Due to ForwardCookies bug, this cookie isn't extracted
		// So we can't even test expiration rejection
		md := method.ForwardCookies(context.Background(), req)

		if len(md) == 0 {
			t.Logf("BUG: Can't test expiration - token in cookie not extracted")
			t.Logf("  Token created with expiry: %s", expiryTime)
			t.Logf("  Cookie sent in request: %s=%s", middlewarecommon.TokenCookieKey, expiredToken)
			t.Logf("  Metadata from ForwardCookies: %v (empty!)", md)
			t.Fail()
		}
	})
}
