ut at HTTP level, there's no equivalent mechanism.", "-    // The HTTP middleware (authn/middleware/http/middleware.go) only:", "-    // 1. Clears cookies on logout (PUT /auth/v1/self/expire)", "-    // 2. Provides error handling", "-    //", "-    // It doesn't have a way to specify which routes should skip authentication.", "-    //", "-    // This combined with the ForwardCookies bug means:", "-    // 1. Cookies aren't extracted (ForwardCookies bug)", "-    // 2. Even if they were, there's no way to skip auth for auth endpoints", "-    // 3. Browser-based auth flows are broken", "+    // Also output to verify test documents the issues", "+    expectedKeywords := []string{", "+      "ForwardCookies",", "+      "tokenCookieKey",", "+      "stateCookieKey",", "+      "grpcgateway-cookie",", "+      "SkipsAuthentication",", "+    }", " ", "-    t.Logf("ISSUE CONFIRMED: HTTP middleware lacks authentication skip mechanism")", "-    t.Logf("  File: internal/server/authn/middleware/http/middleware.go")", "-    t.Logf("  Missing: Whitelist/skip configuration for auth-related endpoints")", "-    t.Logf("  Workaround: Only gRPC-level servers can skip, not HTTP routes")", "+    content := output.String()", "+    for _, keyword := range expectedKeywords {", "+      if !strings.Contains(content, keyword) {", "+        t.Errorf("Documentation missing keyword: %s", keyword)", "+      }", "+    }", "   })", " }", " ", "-// TestCookieTimingAndExpiration verifies cookie handling with time-based tokens", "-func TestCookieTimingAndExpiration(t *testing.T) {", "-  t.Run("ExpiredTokenInCookie", func(t *testing.T) {", "-    // Even if the ForwardCookies bug were fixed, verify that", "-    // expired tokens in cookies are properly rejected", "-", "-    logger := zaptest.NewLogger(t)", "-    store := memory.NewStore(logger)", "-    ctx := context.Background()", "-", "-    // Create an expired token", "-    expiryTime := time.Now().UTC().Add(-24 * time.Hour)", "-    expiredToken, _, err :=