		//
		// File: internal/server/authn/middleware/grpc/middleware.go
		// Lines: 88-110
		//
		// It supports:
		//   1. SkipsAuthenticationServer interface: type SkipsAuthenticationServer interface {
		//                                              SkipsAuthentication(ctx context.Context) bool
		//                                          }
		//   2. WithServerSkipsAuthentication option: to register servers that skip auth
		//   3. Check: if skipSrv, ok := server.(SkipsAuthenticationServer); ok && skipSrv.SkipsAuthentication(ctx) {...}
		//
		// However, the HTTP middleware (gRPC Gateway) has NO equivalent:
		//
		// File: internal/server/authn/middleware/http/middleware.go
		// Lines: 32-45
		//
		// It only:
