// TestRegression tests for authentication cookie handling bugs in Flipt
func TestRegression(t *testing.T) {
	t.Run("BUG1_CookieForwardingTypo_Documented", func(t *testing.T) {
		// This test documents the exact bug in ForwardCookies
		//
		// File: internal/server/authn/method/http.go
		// Function: ForwardCookies
		// Lines: 47-56 (approximate)
		//
		// Bug Code:
		//   for _, key := range []string{stateCookieKey, tokenCookieKey} {
		//       if cookie, err := req.Cookie(key); err == nil {
		//           md[stateCookieKey] = []string{cookie.Value}  // BUG HERE
		//       }
		//   }
		//
		// Problem: The variable 'key' is never used in the assignment.
		// It always uses the hardcoded 'stateCookieKey'.
		//
		// When processing:
		//   - stateCookieKey: correctly assigns md["flipt_client_state"] = cookie.Value
		//   - tokenCookieKey: SHOULD assign md["flipt_client_token"] = cookie.Value
		//                     BUT instead assigns md["flipt_client_state"] = cookie.Value (overwriting!)
		//                     Then returns without the token!
		//
		// Result: tokenCookieKey is lost, authentication fails for browser clients
		//
		// Verification: This test would fail with current implementation

		const stateKey = "flipt_client_state"
		const tokenKey = "flipt_client_token"

		// Simulate what the buggy code does
		buggyMetadata := make(map[string]string)
		keys := []string{stateKey, tokenKey}

		for _, key := range keys {
			// Simulating: if cookie with key exists
			// Current buggy code:
			buggyMetadata[stateKey] = fmt.Sprintf("value_from_%s", key)
			// This overwrites! tokenKey value never makes it to metadata
		}

		t.Logf("Buggy implementation result:")
		t.Logf("  Input: cookies for both stateKey and tokenKey")
		t.Logf("  Output: %v", buggyMetadata)
		t.Logf("")
		t.Logf("Expected: map[%s:value_from_state %s:value_from_token]", stateKey, tokenKey)
		t.Logf("Actual:   map[%s:value_from_token] (tokenKey is missing!)", stateKey)
		t.Logf("")
		t.Logf("✓ BUG CONFIRMED: tokenCookieKey value is overwritten and lost")

		// Verify the bug logic
		if len(buggyMetadata) != 1 {
			t.Errorf("Expected 1 entry in buggy metadata, got %d", len(buggyMetadata))
		}
		if buggyMetadata[stateKey] != "value_from_token" {
			t.Errorf("Expected buggyMetadata[%q] = 'value_from_token', got %q", stateKey, buggyMetadata[stateKey])
		}

		// Demonstrate correct implementation
		correctMetadata := make(map[string]string)
		for _, key := range keys {
			correctMetadata[key] = fmt.Sprintf("value_from_%s", key)
		}

		t.Logf("")
		t.Logf("Fixed implementation would produce:")
		t.Logf("  %v", correctMetadata)
		if len(correctMetadata) != 2 {
			t.Errorf("Expected 2 entries, got %d", len(correctMetadata))
		}
	})

	t.Run("BUG1_CookieFormatIssue_Documented", func(t *testing.T) {
		// Even if the typo is fixed, the ForwardCookies function has a second issue:
		// The metadata format is wrong for gRPC Gateway.
		//
		// The gRPC middleware expects cookies under "grpcgateway-cookie" key
		// in HTTP Cookie format (e.g., "name=value; name2=value2")
		//
		// Current ForwardCookies puts them directly with cookie name as key,
		// which gRPC middleware can't parse correctly.

		// What gRPC middleware needs to work:
		cookieHeaderKey := "grpcgateway-cookie"
		tokenCookieKey := "flipt_client_token"
		tokenValue := "test_token_abc123"

		// Correct format for gRPC metadata
		correctFormat := map[string][]string{
			cookieHeaderKey: {fmt.Sprintf("%s=%s", tokenCookieKey, tokenValue)},
		}

		t.Logf("Correct metadata format for gRPC Gateway:")
		for k, v := range correctFormat {
			t.Logf("  metadata[%q] = %v", k, v)
		}

		// The middleware parses it like this:
		req := &http.Request{
			Header: http.Header{
				"Cookie": correctFormat[cookieHeaderKey],
			},
		}

		// This parsing should work with correct format
		cookie, err := req.Cookie(tokenCookieKey)
		if err != nil {
			t.Errorf("Failed to parse correctly formatted cookie: %v", err)
		} else {
			t.Logf("✓ Correctly formatted cookie parsed successfully: %s=%s", cookie.Name, cookie.Value)
		}

		// But ForwardCookies likely doesn't produce this format
		t.Logf("")
		t.Logf("ForwardCookies likely produces wrong format like:")
		t.Logf("  metadata[%q] = [%q] (missing gRPC Gateway key!)", tokenCookieKey, tokenValue)
		t.Logf("  Or: metadata keys don't match what gRPC middleware expects")
	})

	t.Run("BUG2_HTTPAuthSkipMechanismMissing_Documented", func(t *testing.T) {
		// The gRPC middleware has authentication skip support:
		//
		// File: internal/server/authn/middleware/grpc/middleware.go
		// Lines: 88-110
		//
		// It supports:
		//   1. SkipsAuthenticationServer interface: type SkipsAuthenticationServer interface {
		//                                              SkipsAuthentication(ctx context.Context) bool
		//                                          }
		//   2. WithServerSkipsAuthentication option: to register servers that skip auth
		//   3. Check: if skipSrv, ok := server.(SkipsAuthenticationServer); ok && skipSrv.SkipsAuthentication(ctx) {...}
		//
		// However, the HTTP middleware (gRPC Gateway) has NO equivalent:
		//
		// File: internal/server/authn/middleware/http/middleware.go
		// Lines: 32-45
		//
		// It only:
		//   1. Clears cookies on logout (PUT /auth/v1/self/expire)
		//   2. Handles error responses
		//
		// Missing:
		//   - No configuration to skip auth for specific routes
		//   - No whitelist mechanism
		//   - No route-based skip logic

		t.Logf("gRPC Middleware Authentication Skip Mechanism:")
		t.Logf("  ✓ SkipsAuthenticationServer interface exists")
		t.Logf("  ✓ WithServerSkipsAuthentication option available")
		t.Logf("  ✓ Middleware checks both: server instance and options")
		t.Logf("  ✓ Used for: PublicAuthService, OIDC, GitHub, Kubernetes")
		t.Logf("")
		t.Logf("HTTP Middleware Authentication Skip Mechanism:")
		t.Logf("  ✗ No SkipsAuthenticationRoute interface")
		t.Logf("  ✗ No WithRouteSkipsAuthentication option")
		t.Logf("  ✗ No whitelist or skip configuration")
		t.Logf("  ✗ All HTTP routes go through same auth middleware")
		t.Logf("")
		t.Logf("Impact:")
		t.Logf("  - Auth-related endpoints (/auth/v1/method/*/authorize) need to skip auth")
		t.Logf("  - But HTTP layer forces authentication on all routes")
		t.Logf("  - This breaks OIDC, GitHub, and other delegated auth flows")
		t.Logf("  - Especially when combined with BUG 1 (cookie forwarding)")

		// Expected behavior
		expectedSkips := map[string]bool{
			"/auth/v1/method/oidc/authorize":                    true,
			"/auth/v1/method/oidc/callback":                     true,
			"/auth/v1/method/github/authorize":                  true,
			"/auth/v1/method/github/callback":                   true,
			"/auth/v1/method/kubernetes/service-account/verify": true,
			"/auth/v1/self/expire":                              false,  // logout still needs auth
			"/api/v1/flags":                                     false,  // regular API needs auth
		}

		t.Logf("")
		t.Logf("Routes that should skip authentication:")
		for route, shouldSkip := range expectedSkips {
			status := "✗"
			if shouldSkip {
				status = "✓"
			}
			t.Logf("  %s %s (skip=%v)", status, route, shouldSkip)
		}
	})

