		//
		// Result: Browser-based authentication is broken

		t.Logf("Browser Authentication Flow - BROKEN:")
		t.Logf("")
		t.Logf("1. User accesses app from browser")
		t.Logf("2. Redirected to /auth/v1/method/oidc/authorize")
		t.Logf("3. ISSUE: This endpoint should not require auth (public endpoint)")
		t.Logf("   But HTTP middleware enforces auth on ALL routes")
		t.Logf("")
		t.Logf("4. After OIDC callback, token is set as HTTP-only cookie")
		t.Logf("5. Browser makes request to /api/v1/flags with cookie")
		t.Logf("6. ISSUE: ForwardCookies doesn't extract the cookie")
		t.Logf("   Metadata is empty or malformed")
		t.Logf("")
		t.Logf("7. gRPC middleware doesn't find auth in metadata")
		t.Logf("8. Request fails with 'unauthenticated' error")
		t.Logf("")
		t.Logf("Root Causes:")
		t.Logf("  BUG 1: Cookie not forwarded to gRPC metadata")
		t.Logf("  BUG 2: Auth endpoints can't skip authentication")
		t.Logf("")
		t.Logf("Result: Browser clients cannot authenticate with Flipt")
	})

